from collections import Counter

class Solution:
    def countAnagrams(self, s):
        MOD = 1000000007
        max_n = len(s) + 1
        fact = [1] * (max_n + 1)
        for i in range(1, max_n + 1):
            fact[i] = fact[i - 1] * i % MOD
        inv_fact = [1] * (max_n + 1)
        inv_fact[max_n] = pow(fact[max_n], MOD - 2, MOD)
        for i in range(max_n, 0, -1):
            inv_fact[i - 1] = inv_fact[i] * i % MOD
        ans = 1
        for word in s.split():
            cnt = Counter(word)
            perm = fact[len(word)]
            for c in cnt.values():
                perm = perm * inv_fact[c] % MOD
            ans = ans * perm % MOD
        return ans

