var countAnagrams = function(s) {
    const MOD = 1000000007n;
    const words = s.split(' ');
    const maxN = s.length + 1;
    const fact = new Array(maxN + 1);
    fact[0] = 1n;
    for (let i = 1; i <= maxN; i++) fact[i] = (fact[i - 1] * BigInt(i)) % MOD;
    function power(base, exp, mod) {
        base %= mod;
        let result = 1n;
        while (exp > 0n) {
            if (exp & 1n) result = (result * base) % mod;
            base = (base * base) % mod;
            exp >>= 1n;
        }
        return result;
    }
    const invFact = new Array(maxN + 1);
    invFact[maxN] = power(fact[maxN], MOD - 2n, MOD);
    for (let i = maxN; i >= 1; i--) invFact[i - 1] = (invFact[i] * BigInt(i)) % MOD;
    let ans = 1n;
    for (const word of words) {
        const cnt = new Map();
        for (const ch of word) cnt.set(ch, (cnt.get(ch) || 0) + 1);
        let perm = fact[word.length];
        for (const c of cnt.values()) {
            perm = (perm * invFact[c]) % MOD;
        }
        ans = (ans * perm) % MOD;
    }
    return Number(ans);
};
